## WebGPU Pipeline Architecture

MapGPU's render engine is built on WebGPU with a delegate-based architecture:

### Draw Delegates

Each visual type has a dedicated delegate responsible for lazy pipeline initialization and draw calls:

| Delegate | Pipeline(s) | Purpose |
|----------|------------|---------|
| DrawDelegateRaster | raster-imagery | Tile imagery rendering |
| DrawDelegatePolygon | polygon-fill | Filled polygons |
| DrawDelegateLine | line | Solid, dashed, animated lines |
| DrawDelegatePoint | point-symbol, icon | Circle markers, icon symbols |
| DrawDelegateModel | model, globe-model | 3D GLTF/GLB models |
| DrawDelegateCustom | custom | User-defined WGSL shaders |

### Frame Context

A shared `FrameContext` object provides centralized GPU state to all delegates:

```typescript
interface FrameContext {
  device: GPUDevice;
  encoder: GPUCommandEncoder;
  passEncoder: GPURenderPassEncoder;
  cameraBuffer: GPUBuffer;
  viewState: ViewState;
  // ...
}
```

## Custom Shaders (WGSLLayer)

Write your own vertex/fragment shaders via `WGSLLayer`:

```typescript
import { WGSLLayer } from '@mapgpu/layers';

const layer = new WGSLLayer({
  id: 'particles',
  vertexShader: `
    @vertex fn vs(@builtin(vertex_index) i: u32) -> @builtin(position) vec4f {
      // Your vertex shader
    }
  `,
  fragmentShader: `
    @fragment fn fs() -> @location(0) vec4f {
      return vec4f(1.0, 0.4, 0.2, 1.0);
    }
  `,
  vertexCount: 1000,
  topology: 'point-list',
});
```

In globe mode (Mode3D), the preamble automatically includes `projectMercator()` with the Y-flip convention.

## WebGPU Capability Detection

MapGPU automatically detects GPU capabilities at initialization:

```typescript
// Auto-detected
const caps = await detectCapabilities();
// caps.mode: 'full-gpu' | 'gpu-lite' | 'cpu-degraded'
```

### Feature Detection

| Feature | Required | Usage |
|---------|---------|-------|
| Basic WebGPU | Yes | Core rendering |
| `timestamp-query` | No | Performance profiling |
| `float32-filterable` | No | Advanced texture filtering |
| `shader-f16` | No | Half-precision optimization |

## GPU Device Lost Handling

MapGPU handles GPU device loss (tab backgrounding, driver crash) with automatic recovery:

1. Release all GPU resources
2. Request new adapter + device
3. Recreate all pipelines
4. Re-upload textures from tile cache
5. Emit `'device-recovered'` or `'device-lost'` event

```typescript
view.on('error', (err) => {
  if (err.kind === 'webgpu-device-lost') {
    console.log('GPU device lost:', err.message);
  }
});
```

import { MapView, ClassBreaksRenderer } from '@mapgpu/core';
import type { ExtrudedPolygonSymbol, ClassBreakInfo } from '@mapgpu/core';
import { RenderEngine } from '@mapgpu/render-webgpu';
import { VectorTileLayer, RasterTileLayer } from '@mapgpu/layers';

const view = new MapView({
  container: document.getElementById('map-container')!,
  center: [28.9784, 41.0082], zoom: 16, renderEngine: new RenderEngine(),
});

view.map.add(new RasterTileLayer({ id: 'osm', urlTemplate: 'https://tile.openstreetmap.org/{z}/{x}/{y}.png' }));

// Height-based color ramp: teal (low) -> yellow (mid) -> red (tall)
const colors: [number, number, number][] = [
  [65, 182, 196], [199, 233, 180], [255, 255, 204],
  [254, 217, 118], [253, 141, 60], [227, 26, 28], [128, 0, 38],
];
const thresholds = [0, 6, 12, 20, 50, 120, 500];

function makeSymbol(color: [number, number, number]): ExtrudedPolygonSymbol {
  return {
    type: 'fill-extrusion', color: [...color, 220],
    heightField: 'render_height', minHeightField: 'render_min_height',
    ambient: 0.35, shininess: 32, specularStrength: 0.15,
    animation: { duration: 1000, delayFactor: 3.0, easing: 'ease-out-cubic' },
  };
}

const breaks: ClassBreakInfo[] = colors.map((c, i) => ({
  min: thresholds[i]!, max: thresholds[i + 1] ?? Infinity, symbol: makeSymbol(c),
}));

const buildings = new VectorTileLayer({
  id: 'buildings-3d',
  url: 'https://tiles.openfreemap.org/planet/20260311_001001_pt/{z}/{x}/{y}.pbf',
  sourceLayer: 'building', minZoom: 13, maxZoom: 14,
  renderer: new ClassBreaksRenderer({ field: 'render_height', defaultSymbol: makeSymbol(colors[2]!), breaks }),
});

view.map.add(buildings);

// Start in 3D with tilted camera
await view.switchTo('3d');
await view.goTo({ pitch: 50, bearing: -20, duration: 600 });

import { MapView, lonLatToMercator } from '@mapgpu/core';
import { RenderEngine } from '@mapgpu/render-webgpu';
import { RasterTileLayer, WGSLLayer } from '@mapgpu/layers';

const VERTEX_SHADER = /* wgsl */ `
struct CustomUniforms { halfWidth: f32, trailSpeed: f32, trailLength: f32, trailCycle: f32 };
struct VertexOutput { @builtin(position) position: vec4<f32>, @location(0) vColor: vec4<f32>, @location(1) vDistSide: vec2<f32> };
@vertex fn vs_main(
  @location(0) pos: vec2<f32>, @location(1) offset: vec2<f32>,
  @location(2) distSide: vec2<f32>, @location(3) color: vec4<f32>,
) -> VertexOutput {
  var out: VertexOutput;
  let clip = projectMercator(pos);
  if (clip.w < 0.0001) { out.position = vec4<f32>(0,0,0.5,1); out.vColor = vec4<f32>(0); out.vDistSide = vec2<f32>(0,100); return out; }
  let clipOff = projectMercator(pos + offset * 50000.0);
  let sc = clip.xy / clip.w; let so = clipOff.xy / clipOff.w;
  let dir = normalize((so - sc) * camera.viewport) / camera.viewport * custom.halfWidth * 2.0;
  out.position = vec4<f32>(clip.xy + dir * clip.w * distSide.y, clip.z, clip.w);
  out.vColor = color; out.vDistSide = distSide; return out;
}`;

const FRAGMENT_SHADER = /* wgsl */ `
@fragment fn fs_main(@location(0) vColor: vec4<f32>, @location(1) vDistSide: vec2<f32>) -> @location(0) vec4<f32> {
  let phase = vDistSide.x - frame.time * custom.trailSpeed;
  let t = phase - custom.trailCycle * floor(phase / custom.trailCycle);
  let head = 1.0 - smoothstep(0.0, custom.trailLength, t);
  let edge = exp(-abs(vDistSide.y) * 3.0);
  let alpha = min(head * edge * frame.opacity * vColor.a, 0.85);
  if (alpha < 0.01) { discard; }
  return vec4<f32>(vColor.rgb * alpha, alpha);
}`;

const engine = new RenderEngine();
const view = new MapView({
  container: document.getElementById('map-container')!,
  center: [32, 39.5], zoom: 6, renderEngine: engine,
});

await view.when();
view.map.add(new RasterTileLayer({ id: 'osm', urlTemplate: 'https://tile.openstreetmap.org/{z}/{x}/{y}.png' }));

const STRIDE = 28;
const layer = new WGSLLayer({
  id: 'animated-lines', vertexShader: VERTEX_SHADER, fragmentShader: FRAGMENT_SHADER,
  vertexBufferLayouts: [{ arrayStride: STRIDE, stepMode: 'vertex', attributes: [
    { shaderLocation: 0, offset: 0, format: 'float32x2' as GPUVertexFormat },
    { shaderLocation: 1, offset: 8, format: 'float32x2' as GPUVertexFormat },
    { shaderLocation: 2, offset: 16, format: 'float32x2' as GPUVertexFormat },
    { shaderLocation: 3, offset: 24, format: 'unorm8x4' as GPUVertexFormat },
  ]}],
  animated: true, topology: 'triangle-list',
  blendState: { color: { srcFactor: 'one', dstFactor: 'one-minus-src-alpha', operation: 'add' },
                alpha: { srcFactor: 'one', dstFactor: 'one-minus-src-alpha', operation: 'add' } },
});
await layer.load();

layer.setCustomUniforms(new Float32Array([4, 500000, 200000, 800000]));
view.map.add(layer);

